-- 1. Create the schema
CREATE SCHEMA IF NOT EXISTS fitness;

-- 2. Trigger Function for timestamps
CREATE OR REPLACE FUNCTION fitness.set_timestamp()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at := CURRENT_TIMESTAMP;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- 3. Exercise Catalog Table
CREATE TABLE IF NOT EXISTS fitness.exercises (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(256) UNIQUE NOT NULL, -- Constraint: Unique & Not Null
    type VARCHAR(32),
    target_area VARCHAR(32),
    primary_muscle VARCHAR(256),
    sec_muscle VARCHAR(256),
    equipment VARCHAR(32),
    mechanic VARCHAR(32),
    difficulty VARCHAR(32),
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- 4. Workout Table
CREATE TABLE IF NOT EXISTS fitness.workouts (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id UUID NOT NULL, -- Linked to Accounts ID
    name VARCHAR(255),
    description TEXT,
    workout_date TIMESTAMPTZ,
    status VARCHAR(32) NOT NULL DEFAULT 'PLANNED' 
        CHECK (status IN ('PLANNED', 'COMPLETED')), -- Constraint: Valid Status
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    deleted_at TIMESTAMPTZ -- For soft deletes/Disaster Recovery
);

-- 5. WorkoutExercise Junction Table
CREATE TABLE IF NOT EXISTS fitness.workout_exercises (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    workout_id UUID NOT NULL REFERENCES fitness.workouts(id) ON DELETE CASCADE, -- Constraint: Cascade
    exercise_id UUID NOT NULL REFERENCES fitness.exercises(id) ON DELETE RESTRICT, -- Constraint: Restrict
    sets INTEGER CHECK (sets > 0),
    reps INTEGER CHECK (reps > 0),
    weight NUMERIC CHECK (weight >= 0),
    duration NUMERIC,
    notes TEXT,
    exercise_order INTEGER,
    created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- 6. Apply Timestamps to all tables
CREATE TRIGGER set_timestamp_exercises BEFORE UPDATE ON fitness.exercises FOR EACH ROW EXECUTE FUNCTION fitness.set_timestamp();
CREATE TRIGGER set_timestamp_workouts BEFORE UPDATE ON fitness.workouts FOR EACH ROW EXECUTE FUNCTION fitness.set_timestamp();
CREATE TRIGGER set_timestamp_workout_exercises BEFORE UPDATE ON fitness.workout_exercises FOR EACH ROW EXECUTE FUNCTION fitness.set_timestamp();

-- 7. Populate Exercise Catalog (Only once)
ON CONFLICT (name) DO NOTHING;